#include <stdio.h>
int main() {
    int N;
    scanf("%d", &N);
    int A[N], L[N], dp[N];
    int prev = 0;
    for (int i = 0; i < N; i++) {
        int A_prime, L_prime;
        scanf("%d %d", &A_prime, &L_prime);
        A[i] = prev ^ A_prime;
        L[i] = prev ^ L_prime;
        dp[i] = 1;
        for (int j = 0; j < i; j++) {
            if (abs(A[i] - A[j]) <= L[i]) {
                dp[i] = (dp[i] > dp[j] + 1) ? dp[i] : dp[j] + 1;
            }
        }
        printf("%d\n", dp[i]);
        prev = A[i];
    }
    return 0;
}

