import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int[] A = new int[N];
        int[] L = new int[N];
        int[] dp = new int[N];
        int prev = 0;
        for (int i = 0; i < N; i++) {
            int A_prime = sc.nextInt();
            int L_prime = sc.nextInt();
            A[i] = prev ^ A_prime;
            L[i] = prev ^ L_prime;
            dp[i] = 1;
            for (int j = 0; j < i; j++) {
                if (Math.abs(A[i] - A[j]) <= L[i]) {
                    dp[i] = Math.max(dp[i], dp[j] + 1);
                }
            }
            System.out.println(dp[i]);
            prev = A[i];
        }
    }
}

